#!/usr/bin/env bun
/**
 * Sanitize OpenAPI spec generated by Elysia
 * 
 * Fixes issues where Elysia generates:
 * 1. Incomplete schema references ($ref without #/components/schemas/ prefix)
 * 2. OpenAPI 3.1 constructs in a 3.0.3 spec:
 *    - patternProperties → additionalProperties (3.1-only keyword)
 *    - anyOf with {type: "null"} → nullable: true (3.0.x pattern)
 *    - {type: "null"} standalone → nullable: true
 * 
 * These cause openapi-generator-cli (Java) to NPE when parsing.
 */

import { readFileSync, writeFileSync } from 'fs'
import { resolve } from 'path'

const OPENAPI_PATH = resolve(import.meta.dir, '../dist/openapi.json')

console.log('🔧 Sanitizing OpenAPI spec...')

// Read the OpenAPI spec
const content = readFileSync(OPENAPI_PATH, 'utf-8')
const spec = JSON.parse(content)

let changeCount = 0

// --- Phase 1: Fix OpenAPI 3.1 constructs for 3.0.3 compatibility ---

/**
 * Recursively convert OpenAPI 3.1 constructs to 3.0.3 equivalents:
 * - patternProperties → additionalProperties with the pattern value's schema
 * - anyOf containing {type: "null"} → non-null type with nullable: true
 * - standalone {type: "null"} → {nullable: true}
 */
function downgradeToOpenApi303(obj: any): void {
  if (!obj || typeof obj !== 'object') return
  if (Array.isArray(obj)) {
    for (const item of obj) downgradeToOpenApi303(item)
    return
  }

  // Convert patternProperties to additionalProperties
  if ('patternProperties' in obj) {
    const patterns = obj.patternProperties
    const patternKeys = Object.keys(patterns)
    // Use the first pattern's schema as the additionalProperties schema
    if (patternKeys.length > 0) {
      const schema = patterns[patternKeys[0]]
      obj.additionalProperties = schema
    } else {
      obj.additionalProperties = true
    }
    delete obj.patternProperties
    // Ensure type is 'object' if not set
    if (!obj.type) obj.type = 'object'
    changeCount++
  }

  // Convert anyOf with null type to nullable
  if ('anyOf' in obj && Array.isArray(obj.anyOf)) {
    const nullIndex = obj.anyOf.findIndex(
      (s: any) => s && typeof s === 'object' && s.type === 'null'
    )
    if (nullIndex !== -1) {
      // Remove the null variant
      const nonNull = obj.anyOf.filter((_: any, i: number) => i !== nullIndex)
      if (nonNull.length === 1) {
        // Single remaining type: flatten and add nullable
        const remaining = nonNull[0]
        delete obj.anyOf
        Object.assign(obj, remaining)
        obj.nullable = true
      } else if (nonNull.length > 1) {
        // Multiple remaining: keep anyOf without null, add nullable
        obj.anyOf = nonNull
        obj.nullable = true
      } else {
        // Only null type — make it nullable with no specific type
        delete obj.anyOf
        obj.nullable = true
      }
      changeCount++
    }
  }

  // Convert standalone {type: "null"} to {nullable: true}
  if (obj.type === 'null') {
    delete obj.type
    obj.nullable = true
    changeCount++
  }

  // Recurse into all nested objects
  for (const key of Object.keys(obj)) {
    if (typeof obj[key] === 'object' && obj[key] !== null) {
      downgradeToOpenApi303(obj[key])
    }
  }
}

console.log('  Downgrading OpenAPI 3.1 constructs to 3.0.3 compatibility...')
downgradeToOpenApi303(spec)

// --- Phase 2: Fix incomplete $ref references ---

// Function to recursively fix $ref in an object
function fixRefs(obj: any): void {
  if (!obj || typeof obj !== 'object') return

  for (const key in obj) {
    if (key === '$ref' && typeof obj[key] === 'string') {
      const ref = obj[key]
      
      // Fix incomplete references that don't start with #
      if (!ref.startsWith('#') && !ref.startsWith('http')) {
        // Check if this schema exists in components
        const schemaName = ref
        const schemaExists = spec.components?.schemas?.[schemaName]
        
        if (schemaExists) {
          // Fix the reference to use proper JSON Pointer
          obj[key] = `#/components/schemas/${ref}`
          changeCount++
          console.log(`  ✓ Fixed incomplete reference: "${ref}" -> "#/components/schemas/${ref}"`)
        } else {
          // For redirect responses (like /authorize, /login, /logout), remove the response
          // since redirects don't have a JSON body
          console.log(`  ⚠ Warning: Schema "${ref}" doesn't exist, will remove response schema`)
          // Return a marker so parent can remove this
          obj._removeMe = true
          changeCount++
        }
      }
    } else if (typeof obj[key] === 'object') {
      fixRefs(obj[key])
      
      // Clean up marked objects
      if (obj[key]?._removeMe) {
        // For redirect endpoints, remove the entire content/application/json section
        if (key === 'schema') {
          delete obj[key]
        }
      }
    }
  }
}

// Fix all references in the spec
fixRefs(spec)

// Clean up responses with empty content for redirect endpoints
function cleanupEmptyResponses(obj: any): void {
  if (!obj || typeof obj !== 'object') return

  for (const key in obj) {
    if (key === 'responses' && typeof obj[key] === 'object') {
      for (const statusCode in obj[key]) {
        const response = obj[key][statusCode]
        if (response.content?.['application/json'] && !response.content['application/json'].schema) {
          // Remove empty content
          delete response.content
          response.description = response.description || 'Redirect response'
          console.log(`  ✓ Removed empty content from response ${statusCode}`)
          changeCount++
        }
      }
    }
    
    if (typeof obj[key] === 'object') {
      cleanupEmptyResponses(obj[key])
    }
  }
}

cleanupEmptyResponses(spec)

// Write the sanitized spec back
const sanitizedJson = JSON.stringify(spec, null, 2)
writeFileSync(OPENAPI_PATH, sanitizedJson)

// Also update the mcp-server copy (which was written before sanitization)
const mcpServerPath = resolve(import.meta.dir, '../../mcp-server/openapi.json')
try {
  writeFileSync(mcpServerPath, sanitizedJson)
  console.log(`  ✓ Updated mcp-server/openapi.json with sanitized spec`)
} catch {
  // mcp-server directory may not exist in all environments
}

if (changeCount > 0) {
  console.log(`✅ Sanitized OpenAPI spec: ${changeCount} changes made`)
} else {
  console.log('✅ OpenAPI spec is already valid, no changes needed')
}
